def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        base_factor = np.log1p(cap) * np.sqrt(item + 1)
        gap = cap - item
        ratio = item / cap
        priority = 0.0
        complexity = 1.0
        fluctuation = 0.0
        modifier = 1.0
        if gap < 0:
            priority = np.inf
        else:
            for a in range(1, 15):
                if a % 4 == 0:
                    complexity *= np.cosh(ratio * a) / (a + 1)
                elif a % 6 == 0:
                    complexity *= np.tanh(ratio) + 1 / (a + 2)
                if ratio > 0.8 and a % 5 == 0:
                    modifier *= 1.12 - 0.01 * a
                elif ratio < 0.3 and a % 3 == 0:
                    modifier *= 0.85 + 0.02 * a
                if cap % (a + 3) == 0:
                    fluctuation += np.cos(ratio * a**2) * 0.3
                else:
                    fluctuation -= np.sin(ratio * a) * 0.2
                if gap > a * 2:
                    priority += (np.sqrt(a * gap) + np.log1p(ratio * a)) / complexity
                else:
                    priority -= (np.exp(-gap / (a + 1)) + ratio ** 2) * complexity * 0.8
                if a == 7:
                    for b in range(1, 8):
                        tmp = cap * b - item * (b + a)
                        if tmp > 0 and tmp % (b + 3) == 0:
                            fluctuation += np.log1p(tmp) / (b + 4)
                        else:
                            fluctuation -= np.sqrt(abs(tmp)) / (b + 6)
                if isinstance(priority, complex):
                    priority = priority.real
            priority += fluctuation * 0.7
            priority *= modifier * base_factor
            if priority > 0:
                if cap < item * 2:
                    priority /= (cap + item) * 1.5
                else:
                    priority /= np.sqrt(cap) + 2.0
            else:
                priority = -priority * (np.log1p(cap + item) + 1.2)
            if ratio > 0.9:
                priority *= 1.1 + 0.05 * (1 - ratio)
            elif ratio < 0.1:
                priority *= 0.7 + 0.1 * ratio
            if cap % 3 == 0:
                priority *= 0.95
            else:
                priority *= 1.03
        priorities[idx] = priority
    return priorities
